const ids = $.steps.extractIds.output.messageIds || [];
let compiled = 'Found ' + ids.length + ' potential invoice emails.\n\n';
ids.forEach((id, i) => {
  compiled += (i + 1) + '. Message ID: ' + id + '\n';
});
return { compiled, emailCount: ids.length };

const d = $.steps.compileEmailMetadata.output;

let prompt = 'You are an expert invoice data extractor and validator. Process the following email inbox data to extract invoice information.\n\n';
prompt += 'INBOX DATA (' + d.emailCount + ' emails matched invoice search):\n';
prompt += d.compiled + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- For each email that appears to be an invoice, extract all financial data\n';
prompt += '- Extract: vendor name, invoice number, invoice date, due date, total amount, currency, tax amount\n';
prompt += '- Extract line items where visible: item description, quantity, unit price, line total\n';
prompt += '- Parse amounts carefully: remove currency symbols for numeric values, note the currency separately\n';
prompt += '- Validate: check totals match line items, dates are reasonable, amounts are positive\n';
prompt += '- Flag any validation warnings\n';
prompt += '- If data is missing, use "N/A"\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "invoices": [\n';
prompt += '    {\n';
prompt += '      "vendor": "company name",\n';
prompt += '      "invoiceNumber": "INV-001",\n';
prompt += '      "invoiceDate": "YYYY-MM-DD",\n';
prompt += '      "dueDate": "YYYY-MM-DD",\n';
prompt += '      "subtotal": "1000.00",\n';
prompt += '      "taxAmount": "100.00",\n';
prompt += '      "totalAmount": "1100.00",\n';
prompt += '      "currency": "USD",\n';
prompt += '      "category": "software|services|supplies|utilities|other",\n';
prompt += '      "status": "pending|paid|overdue",\n';
prompt += '      "lineItems": [{ "description": "", "quantity": 1, "unitPrice": "100.00", "total": "100.00" }],\n';
prompt += '      "validationWarnings": []\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "totalExtracted": 0,\n';
prompt += '  "grandTotal": "sum of all totals",\n';
prompt += '  "currencyBreakdown": { "USD": "0.00" },\n';
prompt += '  "categoryBreakdown": { "software": 0 },\n';
prompt += '  "summary": "brief summary"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiExtract.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { invoices: [], totalExtracted: 0, grandTotal: '0', summary: raw }; }

const ai = $.steps.parseAI.output;
const invoices = ai.invoices || [];

const header = ['Vendor', 'Invoice #', 'Invoice Date', 'Due Date', 'Subtotal', 'Tax', 'Total', 'Currency', 'Category', 'Status', 'Line Items', 'Warnings'];
const rows = invoices.map(inv => [
  inv.vendor || 'N/A',
  inv.invoiceNumber || 'N/A',
  inv.invoiceDate || 'N/A',
  inv.dueDate || 'N/A',
  inv.subtotal || '0',
  inv.taxAmount || '0',
  inv.totalAmount || '0',
  inv.currency || 'USD',
  inv.category || 'other',
  inv.status || 'pending',
  (inv.lineItems || []).map(li => li.description + ' x' + li.quantity).join('; '),
  (inv.validationWarnings || []).join('; ')
]);

const totalRow = ['TOTAL', '', '', '', '', '', ai.grandTotal || '0', '', '', '', '', ''];
const allRows = [header].concat(rows).concat([totalRow]);
return { values: allRows, invoiceCount: invoices.length, grandTotal: ai.grandTotal || '0' };
